sys_variable_value.value:
(function execute(inputs, outputs) {

  var duration_days = inputs.duration_int;

  var task = inputs.task_id;

  var gr_task = new GlideRecord("x_153465_discovert_route_task_instance");

  var gdt = new GlideDate().getDisplayValue();

  if (gr_task.get(task)) {

  	gdt = new TaskerDurationCalculator().calculateDateOfAddedBusinessDays(gr_task, duration_days, gdt);

  	gdt = new TaskerDurationCalculator().calculateEndOfDay(gr_task, gdt);  

  	outputs.suspense_date = gdt; 
  }

})(inputs, outputs);

